    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    aggregated_results = defaultdict(lambda: {'count': 0, 'avg_score': 0.0, 'max_score': -float('inf'), 'min_score': float('inf')})

    for result in search_results:
        # Extract metadata value for grouping
        group_value = result.metadata.get(group_by_field)

        # Handle missing grouping field values
        if group_value is None:
            group_value = 'unknown'

        # Initialize group statistics if not present
        stats = aggregated_results[group_value]

        # Update basic statistics
        stats['count'] += 1
        stats['avg_score'] = (stats['avg_score'] * (stats['count'] - 1) + result.score) / stats['count']
        if result.score > stats['max_score']:
            stats['max_score'] = result.score
        if result.score < stats['min_score']:
            stats['min_score'] = result.score

    # Convert defaultdict to regular dict for cleaner output
    final_results = {}
    for group_value, stats in aggregated_results.items():
        # Ensure min_score doesn't exceed max_score for valid ranges
        if stats['min_score'] > stats['max_score']:
            stats['min_score'] = stats['max_score']

        final_results[group_value] = stats

