                                   (r.metadata.get(group_by_field) is None and group_value == 'unknown')]
                    if group_results:
                        new_stats[field_name] = sum(r.score for r in group_results) / len(group_results)
                    else:
                        new_stats[field_name] = 0.0
                else:
                    # For other fields, extract from result metadata
                    group_results = [r for r in search_results if r.metadata.get(group_by_field) == group_value or 
                                   (r.metadata.get(group_by_field) is None and group_value == 'unknown')]
                    if group_results:
                        field_values = [getattr(r, field_name, None) for r in group_results]
                        # Filter out None values
                        valid_values = [v for v in field_values if v is not None]
                        if valid_values:
